import{_ as e,o as t,c as o,ae as r}from"./chunks/framework.C8MNLDzb.js";const c=JSON.parse('{"title":"集部代表作者","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/zuozhe/ji/集部作者.md","filePath":"docs/sucai/zuozhe/ji/集部作者.md"}'),h={name:"docs/sucai/zuozhe/ji/集部作者.md"};function i(l,a,n,d,u,s){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="集部代表作者" tabindex="-1">集部代表作者 <a class="header-anchor" href="#集部代表作者" aria-label="Permalink to &quot;集部代表作者&quot;">​</a></h1><h2 id="屈原-约公元前340年-公元前278年" tabindex="-1">屈原（约公元前340年-公元前278年） <a class="header-anchor" href="#屈原-约公元前340年-公元前278年" aria-label="Permalink to &quot;屈原（约公元前340年-公元前278年）&quot;">​</a></h2><p>名平，字原，战国时期楚国诗人、政治家。创立&quot;楚辞&quot;体，代表作《离骚》《九歌》《天问》等，是中国文学史上第一位伟大的浪漫主义诗人。</p><h2 id="陶渊明-365年-427年" tabindex="-1">陶渊明（365年-427年） <a class="header-anchor" href="#陶渊明-365年-427年" aria-label="Permalink to &quot;陶渊明（365年-427年）&quot;">​</a></h2><p>名潜，字元亮，号五柳先生，东晋末期诗人、散文家。田园诗派的创始人，代表作《归去来兮辞》《桃花源记》等，人格高洁，被后世尊为&quot;古今隐逸诗人之宗&quot;。</p><h2 id="李白-701年-762年" tabindex="-1">李白（701年-762年） <a class="header-anchor" href="#李白-701年-762年" aria-label="Permalink to &quot;李白（701年-762年）&quot;">​</a></h2><p>字太白，号青莲居士，唐代伟大的浪漫主义诗人。诗歌想象奇特，气势恢宏，代表作《将进酒》《蜀道难》《早发白帝城》等，被后人尊为&quot;诗仙&quot;。</p><h2 id="杜甫-712年-770年" tabindex="-1">杜甫（712年-770年） <a class="header-anchor" href="#杜甫-712年-770年" aria-label="Permalink to &quot;杜甫（712年-770年）&quot;">​</a></h2><p>字子美，号少陵野老，唐代伟大的现实主义诗人。诗作风格沉郁顿挫，反映社会现实，代表作《春望》《茅屋为秋风所破歌》《三吏》《三别》等，被后人尊为&quot;诗圣&quot;。</p><h2 id="白居易-772年-846年" tabindex="-1">白居易（772年-846年） <a class="header-anchor" href="#白居易-772年-846年" aria-label="Permalink to &quot;白居易（772年-846年）&quot;">​</a></h2><p>字乐天，号香山居士，唐代伟大的现实主义诗人。新乐府运动倡导者，诗作通俗易懂，代表作《琵琶行》《长恨歌》《卖炭翁》等。</p><h2 id="王维-701年-761年" tabindex="-1">王维（701年-761年） <a class="header-anchor" href="#王维-701年-761年" aria-label="Permalink to &quot;王维（701年-761年）&quot;">​</a></h2><p>字摩诘，号摩诘居士，唐代诗人、画家。山水田园诗派的代表，苏轼称其&quot;诗中有画，画中有诗&quot;，精通音律、书法、绘画。</p><h2 id="刘禹锡-772年-842年" tabindex="-1">刘禹锡（772年-842年） <a class="header-anchor" href="#刘禹锡-772年-842年" aria-label="Permalink to &quot;刘禹锡（772年-842年）&quot;">​</a></h2><p>字梦得，唐代诗人、文学家、哲学家。与白居易并称&quot;刘白&quot;，诗作《陋室铭》《竹枝词》《乌衣巷》等，风格雄健。</p><h2 id="李商隐-约813年-858年" tabindex="-1">李商隐（约813年-858年） <a class="header-anchor" href="#李商隐-约813年-858年" aria-label="Permalink to &quot;李商隐（约813年-858年）&quot;">​</a></h2><p>字义山，号玉溪生，晚唐诗人。无题诗最为著名，含蓄深婉，情思绵邈，与杜牧并称&quot;小李杜&quot;。</p><h2 id="杜牧-803年-852年" tabindex="-1">杜牧（803年-852年） <a class="header-anchor" href="#杜牧-803年-852年" aria-label="Permalink to &quot;杜牧（803年-852年）&quot;">​</a></h2><p>字牧之，号樊川居士，晚唐诗人。与李商隐并称&quot;小李杜&quot;，诗作俊爽明丽，七绝最为出色，代表作《泊秦淮》《山行》等。</p><h2 id="苏轼-1037年-1101年" tabindex="-1">苏轼（1037年-1101年） <a class="header-anchor" href="#苏轼-1037年-1101年" aria-label="Permalink to &quot;苏轼（1037年-1101年）&quot;">​</a></h2><p>字子瞻，号东坡居士，北宋文学家、书画家。诗、词、文、书、画均有极高成就，开创豪放词派，代表作《念奴娇·赤壁怀古》《水调歌头》等。</p><h2 id="李清照-1084年-约1155年" tabindex="-1">李清照（1084年-约1155年） <a class="header-anchor" href="#李清照-1084年-约1155年" aria-label="Permalink to &quot;李清照（1084年-约1155年）&quot;">​</a></h2><p>号易安居士，宋代女词人。婉约词派的代表，前期词作写闺阁相思，后期感慨身世，代表作《如梦令》《声声慢》《一剪梅》等。</p><h2 id="辛弃疾-1140年-1207年" tabindex="-1">辛弃疾（1140年-1207年） <a class="header-anchor" href="#辛弃疾-1140年-1207年" aria-label="Permalink to &quot;辛弃疾（1140年-1207年）&quot;">​</a></h2><p>字幼安，号稼轩，南宋豪放派词人。词作豪迈激昂，充满爱国热情，与苏轼并称&quot;苏辛&quot;，代表作《青玉案·元夕》《破阵子》等。</p><h2 id="陆游-1125年-1210年" tabindex="-1">陆游（1125年-1210年） <a class="header-anchor" href="#陆游-1125年-1210年" aria-label="Permalink to &quot;陆游（1125年-1210年）&quot;">​</a></h2><p>字务观，号放翁，南宋诗人。一生创作诗歌近万首，诗词风格兼具豪放与婉约，代表作《示儿》《卜算子·咏梅》等。</p><h2 id="柳永-约984年-约1053年" tabindex="-1">柳永（约984年-约1053年） <a class="header-anchor" href="#柳永-约984年-约1053年" aria-label="Permalink to &quot;柳永（约984年-约1053年）&quot;">​</a></h2><p>原名三变，字景庄，北宋词人。婉约词派的代表，词作通俗易懂，&quot;凡有井水饮处，即能歌柳词&quot;，代表作《雨霖铃》《望海潮》等。</p><h2 id="欧阳修-1007年-1072年" tabindex="-1">欧阳修（1007年-1072年） <a class="header-anchor" href="#欧阳修-1007年-1072年" aria-label="Permalink to &quot;欧阳修（1007年-1072年）&quot;">​</a></h2><p>字永叔，号醉翁，晚年又号六一居士，北宋文学家、史学家。领导北宋古文运动，唐宋八大家之一，代表作《醉翁亭记》等。</p><h2 id="王安石-1021年-1086年" tabindex="-1">王安石（1021年-1086年） <a class="header-anchor" href="#王安石-1021年-1086年" aria-label="Permalink to &quot;王安石（1021年-1086年）&quot;">​</a></h2><p>字介甫，号半山，北宋政治家、文学家。唐宋八大家之一，散文峭拔有力，诗作《泊船瓜洲》《明妃曲》等。</p><h2 id="范仲淹-989年-1052年" tabindex="-1">范仲淹（989年-1052年） <a class="header-anchor" href="#范仲淹-989年-1052年" aria-label="Permalink to &quot;范仲淹（989年-1052年）&quot;">​</a></h2><p>字希文，北宋政治家、文学家。先天下之忧而忧，后天下之乐而乐，代表作《岳阳楼记》。</p><h2 id="秦观-1049年-1100年" tabindex="-1">秦观（1049年-1100年） <a class="header-anchor" href="#秦观-1049年-1100年" aria-label="Permalink to &quot;秦观（1049年-1100年）&quot;">​</a></h2><p>字少游，号淮海居士，北宋婉约派词人。苏门四学士之一，词作情韵深长，代表作《鹊桥仙》《满庭芳》等。</p><h2 id="周邦彦-1056年-1121年" tabindex="-1">周邦彦（1056年-1121年） <a class="header-anchor" href="#周邦彦-1056年-1121年" aria-label="Permalink to &quot;周邦彦（1056年-1121年）&quot;">​</a></h2><p>字美成，号清真居士，北宋词人。婉约派集大成者，词作音律精妙，代表作《苏幕遮》《兰陵王》等。</p><h2 id="纳兰性德-1655年-1685年" tabindex="-1">纳兰性德（1655年-1685年） <a class="header-anchor" href="#纳兰性德-1655年-1685年" aria-label="Permalink to &quot;纳兰性德（1655年-1685年）&quot;">​</a></h2><p>原名成德，字容若，号楞伽山人，清代著名词人。满洲正黄旗人，词作清新自然，真挚动人，王国维评价&quot;北宋以来，一人而已&quot;。代表作《木兰花·拟古决绝词》《长相思》等。</p>',41)])])}const p=e(h,[["render",i]]);export{c as __pageData,p as default};
